// ── EMAIL UTILS ────────────────────────────────────
function decodeEmail(b64) {
  try { return atob(b64); } catch(e) { return null; }
}

function maskEmail(b64) {
  const em = decodeEmail(b64);
  if (!em) return '???';
  const [local, domain] = em.split('@');
  if (!domain) return em;
  const [dname, ...tlds] = domain.split('.');
  const maskedLocal = local[0] + '*'.repeat(Math.min(local.length - 1, 5));
  const maskedDomain = dname[0] + '*'.repeat(Math.min(dname.length - 1, 4));
  return `${maskedLocal}@${maskedDomain}.${tlds.join('.')}`;
}

function sendEmail(b64) {
  const em = decodeEmail(b64);
  if (em) window.open('mailto:' + em, '_self');
}

// ── ADD TO CALENDAR ────────────────────────────────
function addToCalendar() {
  const ics = [
    'BEGIN:VCALENDAR',
    'VERSION:2.0',
    'PRODID:-//MHS96//30-Year Reunion//EN',
    'BEGIN:VEVENT',
    'DTSTART:20260731T190000',
    'DTEND:20260731T220000',
    'SUMMARY:Mohonasen Class of 1996 — 30-Year Reunion',
    "DESCRIPTION:Katie O'Byrnes Irish Pub\\n121 Wall Street\\, Schenectady\\, NY 12305\\nHeavy appetizers included. $30/person.\\nGet tickets: https://venmo.com/u/Suz-Lu",
    "LOCATION:Katie O'Byrnes Irish Pub\\, 121 Wall Street\\, Schenectady\\, NY 12305",
    'END:VEVENT',
    'END:VCALENDAR'
  ].join('\r\n');
  const blob = new Blob([ics], { type: 'text/calendar;charset=utf-8' });
  const url  = URL.createObjectURL(blob);
  const a    = document.createElement('a');
  a.href     = url;
  a.download = 'MHS96-30Year-Reunion.ics';
  document.body.appendChild(a);
  a.click();
  document.body.removeChild(a);
  URL.revokeObjectURL(url);
  showToast('📅 Calendar file downloaded — open it to add to your calendar!');
}

// ── CARD PHOTOS (localStorage) ─────────────────────
const CARD_PHOTOS_KEY = 'mhs96_cardphotos';

function getCardPhotos(id) {
  try { return JSON.parse(localStorage.getItem(CARD_PHOTOS_KEY + '_' + id) || '[]'); }
  catch(e) { return []; }
}

function handlePhotoUpload(event, id) {
  const file = event.target.files[0];
  if (!file) return;
  const img = new Image();
  const reader = new FileReader();
  reader.onload = (e) => {
    img.onload = () => {
      const MAX = 240;
      const scale = Math.min(MAX / img.width, MAX / img.height, 1);
      const canvas = document.createElement('canvas');
      canvas.width  = Math.round(img.width  * scale);
      canvas.height = Math.round(img.height * scale);
      canvas.getContext('2d').drawImage(img, 0, 0, canvas.width, canvas.height);
      const dataUrl = canvas.toDataURL('image/jpeg', 0.78);
      const photos = getCardPhotos(id);
      if (photos.length >= 6) photos.shift();
      photos.push(dataUrl);
      localStorage.setItem(CARD_PHOTOS_KEY + '_' + id, JSON.stringify(photos));
      renderClassmates();
      showToast('📸 Photo added!');
    };
    img.src = e.target.result;
  };
  reader.readAsDataURL(file);
  event.target.value = '';
}

function removeCardPhoto(id, index) {
  if (!confirm('Remove this photo?')) return;
  const photos = getCardPhotos(id);
  photos.splice(index, 1);
  localStorage.setItem(CARD_PHOTOS_KEY + '_' + id, JSON.stringify(photos));
  renderClassmates();
}

