// ── TICKET SYSTEM ──────────────────────────────────
function generateConfCode() {
  const chars = 'ABCDEFGHJKLMNPQRSTUVWXYZ23456789';
  let code = 'MHS96-';
  for (let i = 0; i < 6; i++) code += chars[Math.floor(Math.random() * chars.length)];
  return code;
}

function renderAttendeeFields(qty) {
  const container = document.getElementById('attendeeNames');
  if (!container) return;
  const primaryName = document.getElementById('ticketName').value.trim();
  const existing = [];
  container.querySelectorAll('input[data-attendee]').forEach(el => existing.push(el.value));

  if (qty <= 1) { container.innerHTML = ''; return; }

  const inputStyle = `padding:0.55rem 0.9rem;border:2px solid var(--border);border-radius:8px;font-size:0.9rem;width:100%;transition:border 0.2s;box-sizing:border-box;`;
  let html = `<div style="font-size:0.82rem;font-weight:700;text-transform:uppercase;letter-spacing:0.5px;color:var(--dark);margin-bottom:0.5rem;">
    Guest Info <span style="font-weight:400;text-transform:none;color:var(--text-muted);">(optional)</span></div>`;
  for (let i = 1; i < qty; i++) {
    const val = existing[i] || '';
    html += `<div style="border:1px solid var(--border);border-radius:10px;padding:0.85rem;display:flex;flex-direction:column;gap:0.5rem;background:#fafafa;">
      <div style="font-size:0.75rem;font-weight:700;color:var(--text-muted);text-transform:uppercase;letter-spacing:0.4px;">Guest ${i}</div>
      <input type="text" data-attendee="${i}" placeholder="Guest ${i} full name (optional)"
        value="${val.replace(/"/g, '&quot;')}"
        style="${inputStyle}"
        onfocus="this.style.borderColor='var(--orange)'" onblur="this.style.borderColor='var(--border)'">
      <input type="email" data-guest-email="${i}" placeholder="Guest ${i} email (optional)"
        style="${inputStyle}"
        onfocus="this.style.borderColor='var(--orange)'" onblur="this.style.borderColor='var(--border)'">
    </div>`;
  }
  container.innerHTML = html;
}

function syncPrimaryName(el, idx) {
  if (idx === 0) {
    const nameInput = document.getElementById('ticketName');
    if (nameInput) nameInput.value = el.value;
  }
}

function getAttendeeNames(qty) {
  const names = [];
  for (let i = 0; i < qty; i++) {
    const el = document.querySelector(`input[data-attendee="${i}"]`);
    names.push(el ? el.value.trim() : '');
  }
  return names;
}

function updateTicketTotal() {
  const qty = Math.max(1, parseInt(document.getElementById('ticketQty').value) || 1);
  document.getElementById('ticketTotal').textContent = (qty * 30).toFixed(2);
  renderAttendeeFields(qty);
}

function adjustTickets(delta) {
  const input = document.getElementById('ticketQty');
  const newVal = Math.max(1, (parseInt(input.value) || 1) + delta);
  input.value = newVal;
  updateTicketTotal();
}

function updatePayButton() {
  const method = document.querySelector('input[name="payMethod"]:checked')?.value;
  const btn = document.getElementById('rsvpSubmitBtn');
  if (!btn) return;
  if (method === 'venmo') {
    btn.textContent = '🎟 Submit & Purchase Tickets';
  } else {
    btn.textContent = '✅ Submit RSVP';
  }
}

function submitTicketForm(e) {
  e.preventDefault();
  const name  = document.getElementById('ticketName').value.trim();
  const email = document.getElementById('ticketEmail').value.trim();
  const guestEmailInputs = document.querySelectorAll('input[data-guest-email]');
  const guestEmail = Array.from(guestEmailInputs).map(el => el.value.trim()).filter(Boolean).join(', ');
  const qty        = Math.max(1, parseInt(document.getElementById('ticketQty').value) || 1);
  const payMethod  = document.querySelector('input[name="payMethod"]:checked')?.value;

  if (!name)                { showToast('Please enter your name.'); return; }
  if (!email.includes('@')) { showToast('Please enter a valid email address.'); return; }
  if (!payMethod)           { showToast('Please select a payment method.'); return; }

  const attendees = getAttendeeNames(qty);
  if (attendees[0] === '') attendees[0] = name;
  const conf = generateConfCode();

  // Submit to Apps Script (record + send emails)
  const params = new URLSearchParams({
    action:      'rsvp',
    name,
    email,
    qty:         String(qty),
    attendees:   attendees.filter(Boolean).join(', '),
    guestEmail,
    payMethod,
    conf,
  });
  fetch(APPS_SCRIPT_URL + '?' + params.toString()).catch(() => {});

  // Mark RSVP status on classmate card
  recordRsvpFromForm(name, 'going', qty, { conf, email, payMethod, name });

  // Show confirmation modal
  showTicketModal(name, email, qty, conf, attendees, payMethod, guestEmail);

  // If Venmo, open payment page in new tab after brief delay
  if (payMethod === 'venmo') {
    setTimeout(() => window.open('https://venmo.com/u/Suz-Lu', '_blank', 'noopener,noreferrer'), 600);
  }
}

function buildTicketCard(attendeeName, conf, num, total) {
  return `
    <div class="ticket-card">
      <div class="ticket-band">
        <span>MOHONASEN CLASS OF 1996 · 30-YEAR REUNION</span>
      </div>
      <div class="ticket-body">
        <div class="ticket-school">Mohonasen High School — Class of 1996</div>
        <div class="ticket-title">30-Year Reunion</div>
        <div class="ticket-info">
          <div>📅 Friday, July 31, 2026 &nbsp;·&nbsp; 7:00 PM</div>
          <div>📍 Katie O'Byrnes Irish Pub &nbsp;·&nbsp; Schenectady, NY</div>
          <div>👤 ${attendeeName || 'Guest'}</div>
        </div>
      </div>
      <div class="ticket-stub">
        <div class="stub-num">${num}<span>/ ${total}</span></div>
        <div class="stub-conf">${conf}</div>
        <div class="stub-price">$30</div>
      </div>
    </div>`;
}

function buildTicketEmailBody(name, qty, conf, total, attendees, payMethod, guestEmail) {
  const attendeeList = attendees && attendees.length
    ? attendees.map((n, i) => `  ${i === 0 ? 'Primary' : 'Guest ' + i}: ${n || 'Guest'}`).join('\n')
    : `  ${name}`;
  const payLine = payMethod === 'venmo'
    ? `Payment: Venmo @Suz-Lu — please send $${total.toFixed(2)} with note "${conf}"`
    : `Payment: $${total.toFixed(2)} cash or Venmo at the door`;
  return `Hi ${name.split(' ')[0]},

Your RSVP for the Mohonasen High School Class of 1996 Reunion is confirmed!

CONFIRMATION: ${conf}
Name: ${name}
Tickets: ${qty} × $30 = $${total.toFixed(2)}
${payLine}

ATTENDING:
${attendeeList}${guestEmail ? '\nGuest email: ' + guestEmail : ''}

EVENT:
Friday, July 31, 2026 at 7:00 PM
Katie O'Byrnes Irish Pub
121 Wall Street, State Street & Erie Blvd
Schenectady, NY 12305

Heavy appetizers included.
Please bring your confirmation number to the event.

Questions? mohonclass96@gmail.com | mohon96.com
Go Warriors! 🧡🖤`;
}

function showTicketModal(name, email, qty, conf, attendees, payMethod, guestEmail) {
  const total = qty * 30;
  attendees = attendees || [name];
  payMethod = payMethod || 'cash';
  const payLabel = payMethod === 'venmo' ? '📱 Venmo (@Suz-Lu)' : '💵 Cash / Venmo at the door';

  let ticketsHtml = '';
  for (let i = 0; i < qty; i++) ticketsHtml += buildTicketCard(attendees[i] || name, conf, i + 1, qty);
  document.getElementById('ticketCardsContainer').innerHTML = ticketsHtml;
  document.getElementById('tModalConf').textContent  = conf;
  document.getElementById('tModalName').textContent  = name;
  document.getElementById('tModalEmail').textContent = email;
  document.getElementById('tModalQty').textContent   = qty + ' ticket' + (qty > 1 ? 's' : '');
  document.getElementById('tModalTotal').textContent = '$' + total.toFixed(2);

  // Show/update payment row
  let payRow = document.getElementById('tModalPayRow');
  if (!payRow) {
    const totalRow = document.querySelector('.ts-row:last-child');
    payRow = document.createElement('div');
    payRow.id = 'tModalPayRow';
    payRow.className = 'ts-row';
    totalRow?.after(payRow);
  }
  payRow.innerHTML = `<span>Payment</span><strong style="color:${payMethod === 'venmo' ? 'var(--orange)' : 'var(--dark)'};">${payLabel}</strong>`;

  if (payMethod === 'venmo') {
    payRow.insertAdjacentHTML('afterend',
      `<div style="background:#fff8f0;border:1px solid var(--orange);border-radius:8px;padding:0.75rem 1rem;margin-top:0.75rem;font-size:0.85rem;">
        <strong>Next step:</strong> Venmo <strong>@Suz-Lu</strong> $${total.toFixed(2)} and include your confirmation code <strong>${conf}</strong>.
        <a href="https://venmo.com/u/Suz-Lu" target="_blank" rel="noopener" style="display:block;margin-top:0.4rem;color:var(--orange);">Open Venmo →</a>
      </div>`
    );
  }

  const subject = `RSVP Confirmed — Mohonasen Class of '96 Reunion · ${conf}`;
  const body = buildTicketEmailBody(name, qty, conf, total, attendees, payMethod, guestEmail);
  const emailBtn = document.getElementById('emailTicketsBtn');
  const ccPart = guestEmail ? `cc=${encodeURIComponent(guestEmail)}&` : '';
  emailBtn.href = `mailto:${encodeURIComponent(email)}?${ccPart}subject=${encodeURIComponent(subject)}&body=${encodeURIComponent(body)}`;
  emailBtn.textContent = payMethod === 'venmo' ? '📧 Email My RSVP & Payment Info' : '📧 Email My Tickets';

  // Refund request button
  const refundBtn = document.getElementById('refundRequestBtn');
  if (refundBtn) {
    const refundSubject = `Refund Request — ${name} · ${conf}`;
    const refundBody = `Hi,\n\nI need to request a refund for my reunion ticket.\n\nName: ${name}\nConfirmation: ${conf}\nTickets: ${qty}\nTotal: $${total.toFixed(2)}\n\nThank you.`;
    refundBtn.href = `mailto:juliedion1@gmail.com,mohonclass96@gmail.com?subject=${encodeURIComponent(refundSubject)}&body=${encodeURIComponent(refundBody)}`;
  }

  document.getElementById('ticketModal').classList.add('active');
}

function closeTicketModal() {
  document.getElementById('ticketModal').classList.remove('active');
}

function printTickets() {
  const container = document.getElementById('ticketCardsContainer');
  const printArea  = document.getElementById('ticketPrintArea');
  if (printArea) {
    printArea.innerHTML = container.innerHTML;
  } else {
    const div = document.createElement('div');
    div.id = 'ticketPrintArea';
    div.innerHTML = container.innerHTML;
    document.body.appendChild(div);
  }
  window.print();
}

function initTicketForm() {
  const form = document.getElementById('rsvpForm') || document.getElementById('ticketForm');
  if (form) form.addEventListener('submit', submitTicketForm);
  const qtyInput = document.getElementById('ticketQty');
  if (qtyInput) qtyInput.addEventListener('input', updateTicketTotal);
  const nameInput = document.getElementById('ticketName');
  if (nameInput) nameInput.addEventListener('input', () => {
    const first = document.querySelector('input[data-attendee="0"]');
    if (first && first.value === '') first.placeholder = nameInput.value || 'Your name';
  });
  // Payment radio → update button label
  document.querySelectorAll('input[name="payMethod"]').forEach(r => r.addEventListener('change', updatePayButton));
  const tModal = document.getElementById('ticketModal');
  if (tModal) tModal.addEventListener('click', e => { if (e.target === tModal) closeTicketModal(); });
  renderAttendeeFields(1);
}
